items.prompt:
Write TypeScript. Implement and `export` a TYPE (not a function) `ParseQuery<S extends string>`
that parses a URL query string literal into an object type at COMPILE TIME:
  ParseQuery<"a=1">          => { a: "1" }
  ParseQuery<"a=1&b=2">      => { a: "1"; b: "2" }
  ParseQuery<"x=hi&y=lo&z=1"> => { x: "hi"; y: "lo"; z: "1" }
  ParseQuery<"">             => {}
Use template-literal types + recursion. This is type-level only — no runtime code, no `any`.
Return ONLY a single ```ts code block.

items.output:
/** Parse a URL query string literal into an object type at compile time. */
export type ParseQuery<S extends string> =
  // Empty query → empty object
  S extends ''
    ? {}
    // Split on the first '&' and merge the result of the head pair with the tail
    : S extends `${infer Pair}&${infer Rest}`
      ? ParsePair<Pair> & ParseQuery<Rest>
      // No more '&' → parse the final pair
      : ParsePair<S>;

/** Turn a single `key=value` fragment into an object `{ key: value }`. */
type ParsePair<P extends string> =
  P extends `${infer K}=${infer V}`
    ? { [K in K]: V }
    : {};

export class EventEmitter<TEvents extends Record<string, unknown[]>> {
  /**
   * Internal storage: for each event name we keep an array of handlers.
   * Handlers are stored in a type‑erased form (unknown arguments) because
   * the concrete tuple type is known only at compile time.
   */
  private readonly handlers = new Map<
    keyof TEvents,
    Array<(...args: unknown[]) => void>
  >();

  /**
   * Register a handler for an event.
   *
   * @param name    Event name – must be a key of `TEvents`.
   * @param handler Function whose parameters exactly match the tuple type
   *                associated with `name` in `TEvents`.
   */
  on<K extends keyof TEvents>(name: K, handler: (...args: TEvents[K]) => void): void {
    let list = this.handlers.get(name);
    if (!list) {
      list = [];
      this.handlers.set(name, list);
    }
    // Store the handler in a type‑erased form; we know it matches `TEvents[K]`.
    list.push(handler as (...args: unknown[]) => void);
  }

  /**
   * Emit an event, invoking all registered handlers in the order they were added.
   *
   * @param name Event name – must be a key of `TEvents`.
   * @param args Arguments that match the tuple type associated with `name`.
   */
  emit<K extends keyof TEvents>(name: K, ...args: TEvents[K]): void {
    const list = this.handlers.get(name);
    if (!list) return;

    for (const h of list) {
      // Cast back to the concrete handler type before invoking.
      (h as (...args: TEvents[K]) => void)(...args);
    }
  }
}

/**
 * A binary heap implementation for numbers.
 * The `compare` function determines the ordering:
 *   - For a min‑heap: (a, b) => a < b
 *   - For a max‑heap: (a, b) => a > b
 */
class BinaryHeap {
  private data: number[];
  private compare: (a: number, b: number) => boolean;

  constructor(compare: (a: number, b: number) => boolean) {
    this.data = [];
    this.compare = compare;
  }

  /** Number of elements in the heap. */
  size(): number {
    return this.data.length;
  }

  /** Returns the top element without removing it. */
  peek(): number {
    if (this.size() === 0) throw new Error('Heap is empty');
    return this.data[0];
  }

  /** Inserts a value into the heap. */
  push(value: number): void {
    this.data.push(value);
    this.bubbleUp(this.size() - 1);
  }

  /** Removes and returns the top element. */
  pop(): number {
    if (this.size() === 0) throw new Error('Heap is empty');
    const top = this.data[0];
    const last = this.data.pop()!;
    if (this.size() > 0) {
      this.data[0] = last;
      this.bubbleDown(0);
    }
    return top;
  }

  private bubbleUp(index: number): void {
    while (index > 0) {
      const parent = Math.floor((index - 1) / 2);
      if (this.compare(this.data[index], this.data[parent])) {
        [this.data[index], this.data[parent]] = [this.data[parent], this.data[index]];
        index = parent;
      } else {
        break;
      }
    }
  }

  private bubbleDown(index: number): void {
    const length = this.size();
    while (true) {
      let left = index * 2 + 1;
      let right = index * 2 + 2;
      let candidate = index;

      if (left < length && this.compare(this.data[left], this.data[candidate])) {
        candidate = left;
      }
      if (right < length && this.compare(this.data[right], this.data[candidate])) {
        candidate = right;
      }

      if (candidate !== index) {
        [this.data[index], this.data[candidate]] = [this.data[candidate], this.data[index]];
        index = candidate;
      } else {
        break;
      }
    }
  }
}

/**
 * MedianStream maintains a running median of an incoming numeric stream.
 *
 *   const ms = new MedianStream();
 *   ms.add(5);
 *   console.log(ms.median()); // 5
 *
 * The implementation uses two heaps:
 *   - `lower` (max‑heap) stores the smaller half of numbers.
 *   - `higher` (min‑heap) stores the larger half of numbers.
 *
 * The median is either the top of the larger heap (odd count) or
 * the average of both tops (even count).
 */
export class MedianStream {
  private lower: BinaryHeap; // max‑heap for the lower half
  private higher: BinaryHeap; // min‑heap for the upper half

  constructor() {
    this.lower = new BinaryHeap((a, b) => a > b); // max‑heap
    this.higher = new BinaryHeap((a, b) => a < b); // min‑heap
  }

  /** Inserts a number into the stream. */
  add(n: number): void {
    // Decide which heap receives the new value.
    if (this.lower.size() === 0 || n <= this.lower.peek()) {
      this.lower.push(n);
    } else {
      this.higher.push(n);
    }

    // Rebalance to keep size difference ≤ 1.
    if (this.lower.size() > this.higher.size() + 1) {
      this.higher.push(this.lower.pop());
    } else if (this.higher.size() > this.lower.size() + 1) {
      this.lower.push(this.higher.pop());
    }
  }

  /** Returns the current median. Throws if no elements have been added. */
  median(): number {
    const total = this.lower.size() + this.higher.size();
    if (total === 0) {
      throw new Error('MedianStream is empty – no elements to compute a median.');
    }

    if (this.lower.size() === this.higher.size()) {
      // Even number of elements: average the two middle values.
      return (this.lower.peek() + this.higher.peek()) / 2;
    } else if (this.lower.size() > this.higher.size()) {
      // Lower half has the extra element.
      return this.lower.peek();
    } else {
      // Upper half has the extra element.
      return this.higher.peek();
    }
  }
}
